onClick:
{{
  (() => {
// 1. Sinaliza atividade para o sistema de segurança (reseta os 15 min)
 JSutils.resetInactivityTimer();		
// 2 - Definimos os dados que vêm dos inputs do seu formulário/container
		const formData = {
	imun001_id:			(InputID.text),
	imun001_desc: 		(InputNome.text).trim().toUpperCase(),
	imun001_prazo_dias: 		(InputPrazo.text),			
	imun001_ani001_id:          (Select1Especie.selectedOptionValue),
	imun001_imuni004_id:          (Select2Forma.selectedOptionValue),
	imun001_imuni005_id:          (Select3Via.selectedOptionValue)		
    };

    if (appsmith.store.modalContexto?.acaoTipo === "ADICIONAR") {
      return JSconfirmation.showModal({
        action: "Insert",
        message: "Deseja salvar este novo registro?",
        icon: "plus",
        color: "green",
				row: formData
      });
    } else {
      return JSconfirmation.showModal({
        action: "Update",
        message: "Deseja salvar as alterações deste registro?",
        icon: "edit",
        color: "orange",
		    row: formData
      });
    }
  })()
}}
